CREATE TABLE IF NOT EXISTS payment_history (id uuid DEFAULT gen_random_uuid() PRIMARY KEY, student_id uuid REFERENCES auth.users(id) ON DELETE CASCADE, event_type text NOT NULL, amount_usd numeric DEFAULT 0, payment_method text DEFAULT 'none', notes text, created_by text, created_at timestamptz DEFAULT now()); ALTER TABLE payment_history ENABLE ROW LEVEL SECURITY; CREATE POLICY IF NOT EXISTS "student_view_own_payments" ON payment_history FOR SELECT USING (auth.uid() = student_id); CREATE POLICY IF NOT EXISTS "student_insert_own_payments" ON payment_history FOR INSERT WITH CHECK (auth.uid() = student_id);